// To parse this JSON data, do
//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    Directories directories;
    List<String> files;
    Scripts scripts;
    Repository repository;
    String author;
    String license;
    Bugs bugs;
    String homepage;
    DevDependencies devDependencies;
    Engines engines;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.directories,
        required this.files,
        required this.scripts,
        required this.repository,
        required this.author,
        required this.license,
        required this.bugs,
        required this.homepage,
        required this.devDependencies,
        required this.engines,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        directories: Directories.fromJson(json["directories"]),
        files: List<String>.from(json["files"].map((x) => x)),
        scripts: Scripts.fromJson(json["scripts"]),
        repository: Repository.fromJson(json["repository"]),
        author: json["author"],
        license: json["license"],
        bugs: Bugs.fromJson(json["bugs"]),
        homepage: json["homepage"],
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        engines: Engines.fromJson(json["engines"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "directories": directories.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
        "scripts": scripts.toJson(),
        "repository": repository.toJson(),
        "author": author,
        "license": license,
        "bugs": bugs.toJson(),
        "homepage": homepage,
        "devDependencies": devDependencies.toJson(),
        "engines": engines.toJson(),
    };
}

class Bugs {
    String url;

    Bugs({
        required this.url,
    });

    factory Bugs.fromJson(Map<String, dynamic> json) => Bugs(
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "url": url,
    };
}

class DevDependencies {
    String typesChai;
    String typesEnsurePosixPath;
    String typesMocha;
    String typesNode;
    String chai;
    String ensurePosixPath;
    String mocha;
    String typescript;

    DevDependencies({
        required this.typesChai,
        required this.typesEnsurePosixPath,
        required this.typesMocha,
        required this.typesNode,
        required this.chai,
        required this.ensurePosixPath,
        required this.mocha,
        required this.typescript,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        typesChai: json["@types/chai"],
        typesEnsurePosixPath: json["@types/ensure-posix-path"],
        typesMocha: json["@types/mocha"],
        typesNode: json["@types/node"],
        chai: json["chai"],
        ensurePosixPath: json["ensure-posix-path"],
        mocha: json["mocha"],
        typescript: json["typescript"],
    );

    Map<String, dynamic> toJson() => {
        "@types/chai": typesChai,
        "@types/ensure-posix-path": typesEnsurePosixPath,
        "@types/mocha": typesMocha,
        "@types/node": typesNode,
        "chai": chai,
        "ensure-posix-path": ensurePosixPath,
        "mocha": mocha,
        "typescript": typescript,
    };
}

